const staticData = $getWorkflowStaticData('global');
const sessions = staticData.multiIntentAssistantSessions ?? (staticData.multiIntentAssistantSessions = {});

const incoming = items[0]?.json ?? {};
const sessionId = String(
  incoming.sessionId ??
  incoming.chatSessionId ??
  incoming.session_id ??
  incoming.userId ??
  'default-session'
);
const chatInput = String(
  incoming.chatInput ??
  incoming.text ??
  incoming.message ??
  ''
).trim();

const existingSession = sessions[sessionId] ?? {
  phase: 'welcome',
  authenticated: false,
  authAttempts: 0,
  userId: null,
  name: null,
  pendingIntents: [],
  intents: []
};

const mockUsers = {
  '5673': { name: 'Devin', pin: '1234' },
  '2468': { name: 'Ava', pin: '4321' },
  '1357': { name: 'Sam', pin: '2468' }
};

const hasId = /\b(?:user\s*id|id)\D*(\d{3,})\b/i.test(chatInput);
const hasPin = /\bpin\D*(\d{4})\b/i.test(chatInput);
const looksLikeCredentials = hasId && hasPin;

return [
  {
    json: {
      ...incoming,
      sessionId,
      chatInput,
      session: existingSession,
      looksLikeCredentials,
      mockUsers,
      text: incoming.text ?? ''
    }
  }
];

const staticData = $getWorkflowStaticData('global');
const sessions = staticData.multiIntentAssistantSessions ?? (staticData.multiIntentAssistantSessions = {});

const data = items[0].json;
const { sessionId, session, looksLikeCredentials, chatInput } = data;

if (session.authenticated) {
  return [
    {
      json: {
        ...data,
        skipAuth: true,
        text: data.text ?? ''
      }
    }
  ];
}

if (session.phase === 'welcome' && !looksLikeCredentials) {
  const updatedSession = {
    ...session,
    phase: 'awaiting_auth'
  };
  sessions[sessionId] = updatedSession;

  return [
    {
      json: {
        ...data,
        session: updatedSession,
        skipAuth: true,
        text: 'Hi, please share your user ID and 4-digit PIN to continue.'
      }
    }
  ];
}

return [
  {
    json: {
      ...data,
      skipAuth: false,
      text: chatInput ? data.text : 'Hi, please share your user ID and 4-digit PIN to continue.'
    }
  }
];

const staticData = $getWorkflowStaticData('global');
const sessions = staticData.multiIntentAssistantSessions ?? (staticData.multiIntentAssistantSessions = {});

const data = items[0].json;
const { sessionId, session, chatInput, mockUsers, skipAuth } = data;

if (skipAuth) {
  return [{ json: { ...data, authValidated: false, shouldSaveUser: false } }];
}

const idMatch = chatInput.match(/\b(?:user\s*id|id)\D*(\d{3,})\b/i);
const pinMatch = chatInput.match(/\bpin\D*(\d{4})\b/i);

if (!idMatch || !pinMatch) {
  const updatedSession = {
    ...session,
    phase: 'awaiting_auth',
    authAttempts: session.authAttempts ?? 0
  };
  sessions[sessionId] = updatedSession;

  return [
    {
      json: {
        ...data,
        session: updatedSession,
        authValidated: false,
        shouldSaveUser: false,
        text: 'Please send both your user ID and a 4-digit PIN in one message. Example: user id 5673 and pin 1234.'
      }
    }
  ];
}

const userId = idMatch[1];
const pin = pinMatch[1];
const user = mockUsers[userId];
const isValid = Boolean(user && user.pin === pin);

if (!isValid) {
  const updatedSession = {
    ...session,
    phase: 'awaiting_auth',
    authAttempts: (session.authAttempts ?? 0) + 1
  };
  sessions[sessionId] = updatedSession;

  return [
    {
      json: {
        ...data,
        session: updatedSession,
        authValidated: false,
        shouldSaveUser: false,
        attemptedUserId: userId,
        text: 'Authentication failed. Please re-enter your user ID and 4-digit PIN.'
      }
    }
  ];
}

return [
  {
    json: {
      ...data,
      authValidated: true,
      shouldSaveUser: true,
      authenticatedUserId: userId,
      authenticatedName: user.name,
      text: 'Authentication successful.'
    }
  }
];

const staticData = $getWorkflowStaticData('global');
const sessions = staticData.multiIntentAssistantSessions ?? (staticData.multiIntentAssistantSessions = {});

const data = items[0].json;
const { sessionId, session, shouldSaveUser, authenticatedUserId, authenticatedName, skipAuth } = data;

if (skipAuth || !shouldSaveUser) {
  return [{ json: data }];
}

const updatedSession = {
  ...session,
  phase: 'intent_capture',
  authenticated: true,
  authAttempts: 0,
  userId: authenticatedUserId,
  name: authenticatedName,
  pendingIntents: session.pendingIntents ?? [],
  intents: session.intents ?? []
};

sessions[sessionId] = updatedSession;

return [
  {
    json: {
      ...data,
      session: updatedSession,
      sessionState: {
        phase: updatedSession.phase,
        authenticated: updatedSession.authenticated,
        authAttempts: updatedSession.authAttempts,
        userId: updatedSession.userId,
        name: updatedSession.name
      },
      savedUser: {
        userId: authenticatedUserId,
        name: authenticatedName
      },
      text: `Hi ${authenticatedName}, how can I help you today?`
    }
  }
];

const staticData = $getWorkflowStaticData('global');
const sessions = staticData.multiIntentAssistantSessions ?? (staticData.multiIntentAssistantSessions = {});

const data = items[0].json;
const currentSession = sessions[data.sessionId] ?? data.session;

function parseIntents(message) {
  const text = String(message ?? '').trim();
  if (!text) return [];

  const lowered = text.toLowerCase();
  const intents = [];

  const currencyMatch = lowered.match(/\b(?:usd|eur|gbp|inr|aud|cad|jpy|aed|chf|sgd)\b.*\b(?:to|in)\b.*\b(?:usd|eur|gbp|inr|aud|cad|jpy|aed|chf|sgd)\b|\b(?:convert|conversion|exchange rate|currency|rate)\b/);
  if (currencyMatch) {
    intents.push({
      type: 'currency_converter',
      label: 'currency conversion',
      request: text,
      order: currencyMatch.index ?? 0
    });
  }

  const explicitDateTimeRequest = /\b(?:date|time)\b|\bwhat(?:'s| is)?\s+the\s+(?:date|time)\b|\bwhat\s+day\b|\bcoming\s+(?:monday|tuesday|wednesday|thursday|friday|saturday|sunday)\b|\bdate\s+on\b|\btime\s+on\b|\b\d+\s+(?:hours?|days?|weeks?|months?|years?)\s+from\s+now\b|\bnow\b/i;
  const weakTemporalOnly = /\b(?:today|tomorrow|yesterday|next\s+(?:monday|tuesday|wednesday|thursday|friday|saturday|sunday)|coming\s+(?:monday|tuesday|wednesday|thursday|friday|saturday|sunday))\b/i;

  const shouldAddDateTime = explicitDateTimeRequest.test(text) || (!currencyMatch && weakTemporalOnly.test(text));
  const datetimeMatch = shouldAddDateTime ? lowered.match(/\b(?:date|time|today|tomorrow|yesterday|next|coming|monday|tuesday|wednesday|thursday|friday|saturday|sunday|hour|hours|minute|minutes|day|days|week|weeks|month|months|year|years|now)\b/) : null;
  if (datetimeMatch) {
    intents.push({
      type: 'natural_language_datetime',
      label: 'natural language date and time',
      request: text,
      order: datetimeMatch.index ?? 9999
    });
  }

  intents.sort((a, b) => a.order - b.order);

  const seen = new Set();
  return intents.filter((intent) => {
    if (seen.has(intent.type)) return false;
    seen.add(intent.type);
    return true;
  }).map(({ order, ...intent }) => intent);
}

function classifyUnsupported(message) {
  return /\b(?:weather|joke|email|calendar|alarm|reminder|news|book|flight|hotel|pizza|translate|summary|summarize|stock|music|song|play)\b/i.test(message);
}

if (!currentSession.authenticated) {
  return [{ json: data }];
}

if (data.shouldSaveUser) {
  return [{ json: data }];
}

if (currentSession.phase !== 'intent_capture') {
  return [{ json: { ...data, session: currentSession } }];
}

const chatInput = String(data.chatInput ?? '').trim();
if (!chatInput) {
  return [{
    json: {
      ...data,
      session: currentSession,
      intentDetectionStatus: 'no_intent',
      detectedIntents: [],
      text: `Hi ${currentSession.name}, I can help with currency conversion and natural language date or time questions. What would you like to do?`
    }
  }];
}

const detectedIntents = parseIntents(chatInput);
if (detectedIntents.length === 0) {
  const detectionStatus = classifyUnsupported(chatInput) ? 'invalid_intent' : 'no_intent';
  return [{
    json: {
      ...data,
      session: currentSession,
      intentDetectionStatus: detectionStatus,
      detectedIntents: [],
      text: data.text ?? ''
    }
  }];
}

return [{
  json: {
    ...data,
    session: currentSession,
    intentDetectionStatus: 'valid',
    detectedIntents,
    text: data.text ?? ''
  }
}];

const data = items[0].json;
const session = data.session;

if (!session?.authenticated || data.shouldSaveUser || session.phase !== 'intent_capture') {
  return [{ json: data }];
}

if (data.intentDetectionStatus === 'no_intent') {
  return [{
    json: {
      ...data,
      text: `I can help with currency conversion and natural language date or time questions. Please tell me which of those you need.`
    }
  }];
}

if (data.intentDetectionStatus === 'invalid_intent') {
  return [{
    json: {
      ...data,
      text: 'I currently support only currency conversion and natural language date or time requests. Please try one of those.'
    }
  }];
}

return [{ json: data }];

const staticData = $getWorkflowStaticData('global');
const sessions = staticData.multiIntentAssistantSessions ?? (staticData.multiIntentAssistantSessions = {});

const data = items[0].json;
const currentSession = sessions[data.sessionId] ?? data.session;

function summarizeIntents(intents) {
  if (!Array.isArray(intents) || intents.length === 0) return 'no intents';
  if (intents.length === 1) return intents[0].request;
  if (intents.length === 2) return `${intents[0].request} and ${intents[1].request}`;
  return `${intents.slice(0, -1).map((intent) => intent.request).join(', ')}, and ${intents[intents.length - 1].request}`;
}

if (!currentSession?.authenticated || data.shouldSaveUser) {
  return [{ json: data }];
}

if (currentSession.phase !== 'intent_capture' || data.intentDetectionStatus !== 'valid') {
  return [{ json: { ...data, session: currentSession } }];
}

const updatedSession = {
  ...currentSession,
  phase: 'intent_confirmation',
  pendingIntents: data.detectedIntents
};

sessions[data.sessionId] = updatedSession;

const summary = summarizeIntents(updatedSession.pendingIntents);

return [{
  json: {
    ...data,
    session: updatedSession,
    awaitingConfirmation: true,
    pendingIntents: updatedSession.pendingIntents,
    text: `Sure, I can help you with ${summary}. Reply with proceed, add another request, or remove one.`
  }
}];

