  return intents.filter((intent) => {
    if (seen.has(intent.type)) return false;
    seen.add(intent.type);
    return true;
  }).map(({ order, ...intent }) => intent);
}

function mergeIntents(existing, additions) {
  const merged = [...existing];
  const seen = new Set(existing.map((intent) => intent.type));
  for (const intent of additions) {
    if (!seen.has(intent.type)) {
      merged.push(intent);
      seen.add(intent.type);
    }
  }
  return merged;
}

function summarizeIntents(intents) {
  if (!Array.isArray(intents) || intents.length === 0) return 'no intents';
  if (intents.length === 1) return intents[0].request;
  if (intents.length === 2) return `${intents[0].request} and ${intents[1].request}`;
  return `${intents.slice(0, -1).map((intent) => intent.request).join(', ')}, and ${intents[intents.length - 1].request}`;
}

if (!currentSession?.authenticated || currentSession.phase !== 'intent_confirmation') {
  return [{ json: { ...data, session: currentSession } }];
}

if (data.awaitingConfirmation) {
  return [{ json: { ...data, session: currentSession } }];
}

const input = String(data.chatInput ?? '').trim();
const lowered = input.toLowerCase();
const pendingIntents = Array.isArray(currentSession.pendingIntents) ? currentSession.pendingIntents : [];

const proceedIntent = /\b(?:proceed|confirm|confirmed|yes|yes proceed|looks good|that works|done)\b/i.test(input) || /\b(?:no,? that'?s it|that's it|that is it|nothing else|no more)\b/i.test(input);
if (proceedIntent) {
  return [{
    json: {
      ...data,
      session: currentSession,
      shouldSaveIntents: true,
      pendingIntents,
      text: `Thanks. I am saving ${summarizeIntents(pendingIntents)} for processing.`
    }
  }];
}

const removeCurrency = /\bremove\b.*\bcurrency\b|\bwithout\b.*\bcurrency\b|\bdon'?t\b.*\bcurrency\b/i.test(input);
const removeDatetime = /\bremove\b.*\b(?:date|time)\b|\bwithout\b.*\b(?:date|time)\b|\bdon'?t\b.*\b(?:date|time)\b/i.test(input);
if (removeCurrency || removeDatetime) {
  const filtered = pendingIntents.filter((intent) => {
    if (removeCurrency && intent.type === 'currency_converter') return false;
    if (removeDatetime && intent.type === 'natural_language_datetime') return false;
    return true;
  });

  if (filtered.length === 0) {
    const updatedSession = {
      ...currentSession,
      phase: 'intent_capture',
      pendingIntents: []
    };
    sessions[data.sessionId] = updatedSession;

    return [{
      json: {
        ...data,
        session: updatedSession,
        shouldSaveIntents: false,
        pendingIntents: [],
        text: 'All pending intents were removed. Please share a currency conversion or natural language date or time request.'
      }
    }];
  }

  const updatedSession = {
    ...currentSession,
    pendingIntents: filtered
  };
  sessions[data.sessionId] = updatedSession;

  return [{
    json: {
      ...data,
      session: updatedSession,
      shouldSaveIntents: false,
      pendingIntents: filtered,
      text: `Updated intents: ${summarizeIntents(filtered)}. Reply with proceed, add another request, or remove one.`
    }
  }];
}

const additionalIntents = parseIntents(input);
if (additionalIntents.length > 0) {
  const merged = mergeIntents(pendingIntents, additionalIntents);
  const updatedSession = {
    ...currentSession,
    pendingIntents: merged
  };
  sessions[data.sessionId] = updatedSession;

  return [{
    json: {
      ...data,
      session: updatedSession,
      shouldSaveIntents: false,
      pendingIntents: merged,
      text: `Updated intents: ${summarizeIntents(merged)}. Reply with proceed, add another request, or remove one.`
    }
  }];
}

return [{
  json: {
    ...data,
    session: currentSession,
    shouldSaveIntents: false,
    pendingIntents,
    text: 'Please reply with proceed, add another supported request, or remove one of the current intents.'
  }
}];

const staticData = $getWorkflowStaticData('global');
const sessions = staticData.multiIntentAssistantSessions ?? (staticData.multiIntentAssistantSessions = {});

const data = items[0].json;
const currentSession = sessions[data.sessionId] ?? data.session;

function summarizeIntents(intents) {
  if (!Array.isArray(intents) || intents.length === 0) return 'no intents';
  if (intents.length === 1) return intents[0].request;
  if (intents.length === 2) return `${intents[0].request} and ${intents[1].request}`;
  return `${intents.slice(0, -1).map((intent) => intent.request).join(', ')}, and ${intents[intents.length - 1].request}`;
}

if (!data.shouldSaveIntents) {
  return [{ json: { ...data, session: currentSession } }];
}

const intentsToSave = Array.isArray(currentSession.pendingIntents) ? currentSession.pendingIntents : (Array.isArray(data.pendingIntents) ? data.pendingIntents : []);
const updatedSession = {
  ...currentSession,
  phase: 'intent_handler',
  intents: intentsToSave,
  pendingIntents: []
};

sessions[data.sessionId] = updatedSession;

return [{
  json: {
    ...data,
    session: updatedSession,
    sessionState: {
      phase: updatedSession.phase,
      authenticated: updatedSession.authenticated,
      authAttempts: updatedSession.authAttempts,
      userId: updatedSession.userId,
      name: updatedSession.name
    },
    savedIntents: intentsToSave,
    text: `Saved intents: ${summarizeIntents(intentsToSave)}. The workflow is ready for the intent handler step.`
  }
}];
